async (params, browser) => {
  // Open Jira
  await browser.open(`${params.jira_url}/jira/software/projects`)

  // Let Jira load
  await browser.wait(2000)

  // Fetch boards via Agile REST API
  const result = await browser.evaluate(`const baseUrl = params.jira_url.replace(/\/$/, ''); const resp = await fetch(baseUrl + '/rest/agile/1.0/board?maxResults=50', { credentials: 'same-origin' }); if (!resp.ok) throw new Error('Boards API error: ' + resp.status); const data = await resp.json(); const boards = (data.values || []).map(b => ({ id: b.id, name: b.name, type: b.type, project: b.location?.projectName || '' })); return { total: data.total || boards.length, result_count: boards.length, boards: boards }`)

  return result
}
